var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`안녕하세요!`,JPN:`こんにちは！`,ENG:`Hello!`,TWN:`你好！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_SURPRISE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`놀러갈 땐 선물 필요하니까...... 화분 가져왔어요.`,JPN:`遊びに行く時はプレゼントが必要なので……植木鉢を持って来ました。`,ENG:`I've brought a hostess gift... A potted plant.`,TWN:`出去玩的時候需要帶點禮物……所以我帶了花盆來。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`금낭화예요. 저는 포키라고 부르지만...... 원하는 이름을 지어줘도 괜찮아요.`,JPN:`ケマンソウです。私はポッキーと呼んでいますが……好きな名前をつけてあげていいですよ。`,ENG:`It's called a bleeding heart. I call her Pockey, but... you can give her a different name.`,TWN:`這是荷色牡丹，我都叫它波基……不過你如果想取的別的名字也可以。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`헤헤...... 포키로 부르고 싶다니 기뻐요.`,JPN:`えへへ……ポッキーでいいと言ってくれて嬉しいです。`,ENG:`Heh... I'm glad you want to call her Pockey, too.`,TWN:`呵呵……你也想叫它波基嗎？真開心～`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_LAUGH`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`......네? 사장님하고 제가 계약이요?`,JPN:`……え？　社長とあたしが契約ですか？`,ENG:`... Pardon? A contract with you? Me?`,TWN:`……嗯？老闆想和我簽約嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_SURPRISE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`괜찮을까요? 전 싸우는 건...... 좋아하지 않아서요.`,JPN:`いいんですか？　あたしは戦いが……苦手なんです。`,ENG:`Are you sure? But... I don't like fighting.`,TWN:`你確定嗎？我不是很喜歡……打架。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_DESPAIR`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`전 굼뜨기만 하고...... 별로 위협적이지도 않고...... 소심하고.......`,JPN:`あたし、のろまでとろくて……あまり強そうにも見えないし……それに内気で……`,ENG:`I'm not fast, either. Or threatening. I'm too timid, too...`,TWN:`而且我動作很慢……一點威脅性也沒有……又很膽小……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`하지만 사장님은 좋은 친구니까....... 한 번 노력해볼래요.`,JPN:`でも社長はとてもいいお友達ですから……努力してみます。`,ENG:`But you're a good friend. I'll try.`,TWN:`不過老闆是我的好朋友……我會盡量努力看看的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_SERIOUS`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_RA`,text:{KOREA:`그럼...... 포키를 잘 부탁드려요.`,JPN:`それでは……ポッキーをよろしくお願いします。`,ENG:`Then... Please take good care of Pockey.`,TWN:`那麼……波基就麻煩囉！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_RA`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};